62	        macros: vec![
63	            macro_simple(
64	                "Reinforce",
65	                "reinforce",
66	                vec![
67	                    key("KEY_W"), key("KEY_S"), key("KEY_D"),
68	                    key("KEY_W"), key("KEY_A"),
69	                ],
70	            ),
71	            macro_simple(
72	                "Resupply",
73	                "resupply",
74	                vec![
75	                    key("KEY_S"), key("KEY_S"), key("KEY_W"), key("KEY_D"),
76	                ],
77	            ),
78	            macro_simple(
79	                "Eagle Airstrike",
80	                "eagle airstrike",
81	                vec![
82	                    key("KEY_W"), key("KEY_D"), key("KEY_S"), key("KEY_D"),
83	                ],
84	            ),
85	            macro_simple(
86	                "Orbital Laser",
87	                "orbital laser",
88	                vec![
89	                    key("KEY_D"), key("KEY_W"), key("KEY_D"), key("KEY_S"),
90	                    key("KEY_D"),
91	                ],
92	            ),
93	            macro_simple(
94	                "SOS Beacon",
95	                "sos beacon",
96	                vec![
97	                    key("KEY_W"), key("KEY_S"), key("KEY_D"), key("KEY_W"),
98	                ],
99	            ),
100	        ],
101	    };
102	
103	    let support_weapons = Category {
104	        name: "Support Weapons".to_string(),
105	        macros: vec![
106	            macro_simple(
107	                "Anti-Tank Mines",
108	                "anti tank mines",
109	                vec![
110	                    key("KEY_S"), key("KEY_W"), key("KEY_D"), key("KEY_A"),
111	                ],
112	            ),
113	            macro_simple(
114	                "Machine Gun Sentry",
115	                "machine gun sentry",
116	                vec![
117	                    key("KEY_S"), key("KEY_W"), key("KEY_D"), key("KEY_W"),
118	                    key("KEY_A"),
119	                ],
120	            ),
121	        ],
122	    };
123	
124	    let flags = Category {
125	        name: "Flag-gated Stratagems".to_string(),
126	        macros: vec![
127	            macro_with_flags(
128	                "Hellbomb Arm",
129	                "arm hellbomb",
130	                Some("hellbomb_present"),
131	                Some("hellbomb_armed"),
132	                vec![key_timed("KEY_E", 200, 100)],
133	            ),
134	            macro_with_flags(
135	                "Clear Hellbomb Flag",
136	                "hellbomb gone",
137	                None,
138	                Some("hellbomb_armed"),
139	                vec![],
140	            ),
141	        ],
142	    };
143	
144	    Pack {
145	        name: "Helldivers 2".to_string(),
146	        author: Some("community".to_string()),
147	        categories: vec![stratagems, support_weapons, flags],
148	    }
149	}
