58	    /// Import a .hdpack (ZIP) file, extracting into `dest_dir/<pack_name>`.
59	    ///
60	    /// The caller passes the *parent* profiles directory; this function appends
61	    /// the pack name itself — matching the semantics of the original `import`.
62	    pub fn import_to(zip_path: &Path, dest_dir: &Path) -> Result<Self> {
63	        tracing::info!(zip_path = %zip_path.display(), dest_dir = %dest_dir.display(), "import_to: starting");
64	
65	        let file = std::fs::File::open(zip_path)?;
66	        let mut archive = zip::ZipArchive::new(file)?;
67	
68	        // Find pack.yaml to get the pack name
69	        let mut pack_yaml_content = String::new();
70	        {
71	            let mut file = archive.by_name("pack.yaml")
72	                .context("ZIP archive missing pack.yaml")?;
73	            use std::io::Read;
74	            file.read_to_string(&mut pack_yaml_content)?;
75	        }
76	
77	        let pack: Pack = serde_yaml_ng::from_str(&pack_yaml_content)
78	            .context("Failed to parse pack.yaml from ZIP")?;
79	
80	        let pack_dest = dest_dir.join(&pack.name);
81	        if pack_dest.exists() {
82	            std::fs::remove_dir_all(&pack_dest)?;
83	        }
84	        std::fs::create_dir_all(&pack_dest)?;
85	
86	        // Extract all files with path traversal protection
87	        for i in 0..archive.len() {
88	            let mut file = archive.by_index(i)?;
89	            let outpath = match file.enclosed_name() {
90	                Some(path) => pack_dest.join(path),
91	                None => continue,
92	            };
93	
94	            if (*file.name()).ends_with('/') {
95	                std::fs::create_dir_all(&outpath)?;
96	            } else {
97	                if let Some(p) = outpath.parent() {
98	                    if !p.exists() {
99	                        std::fs::create_dir_all(p)?;
100	                    }
101	                }
102	                let mut outfile = std::fs::File::create(&outpath)?;
103	                std::io::copy(&mut file, &mut outfile)?;
104	            }
105	        }
106	
107	        let macro_count = pack.flatten().len();
108	        tracing::info!(zip_path = %zip_path.display(), dest_dir = %pack_dest.display(), macro_count, "import_to: done");
109	
110	        Ok(pack)
111	    }
