119	    /// Export a pack to a .hdpack (ZIP) file.
120	    pub fn export(&self, source_dir: &Path, dest_path: &Path) -> Result<()> {
121	        let file = std::fs::File::create(dest_path)?;
122	        let mut zip = zip::ZipWriter::new(file);
123	        let options = zip::write::FileOptions::default()
124	            .compression_method(zip::CompressionMethod::Stored);
125	
126	        // Write pack.yaml
127	        zip.start_file("pack.yaml", options)?;
128	        let yaml = serde_yaml_ng::to_string(self)?;
129	        use std::io::Write;
130	        zip.write_all(yaml.as_bytes())?;
131	
132	        // Copy sounds/ directory if it exists in the profile dir
133	        let sounds_dir = source_dir.join("sounds");
134	        if sounds_dir.exists() && sounds_dir.is_dir() {
135	            Self::add_dir_to_zip(&mut zip, &sounds_dir, Path::new("sounds"), options)?;
136	        }
137	        
138	        zip.finish()?;
139	        Ok(())
140	    }
