142	    fn add_dir_to_zip<W: std::io::Write + std::io::Seek>(
143	        zip: &mut zip::ZipWriter<W>,
144	        real_path: &Path,
145	        zip_path: &Path,
146	        options: zip::write::FileOptions,
147	    ) -> Result<()> {
148	        for entry in std::fs::read_dir(real_path)? {
149	            let entry = entry?;
150	            let path = entry.path();
151	            let name = entry.file_name();
152	            let new_zip_path = zip_path.join(name);
153	
154	            if path.is_dir() {
155	                // ZIP directories must end with /
156	                let mut dir_name = new_zip_path.to_string_lossy().into_owned();
157	                if !dir_name.ends_with('/') {
158	                    dir_name.push('/');
159	                }
160	                zip.add_directory(dir_name, options)?;
161	                Self::add_dir_to_zip(zip, &path, &new_zip_path, options)?;
162	            } else {
163	                zip.start_file(new_zip_path.to_string_lossy(), options)?;
164	                let mut f = std::fs::File::open(path)?;
165	                std::io::copy(&mut f, zip)?;
166	            }
167	        }
168	        Ok(())
169	    }
170	}
