215	    /// Append `macro_config` to the end of the named category's macro list.
216	    ///
217	    /// Errors if `category` does not exist or if a macro with the same name is already present.
218	    pub fn add_macro(&mut self, category: &str, macro_config: MacroConfig) -> Result<()> {
219	        let cat = self
220	            .pack
221	            .categories
222	            .iter_mut()
223	            .find(|c| c.name == category)
224	            .ok_or_else(|| anyhow::anyhow!("category '{}' not found", category))?;
225	
226	        if cat.macros.iter().any(|m| m.name == macro_config.name) {
227	            bail!(
228	                "macro '{}' already exists in category '{}'",
229	                macro_config.name,
230	                category
231	            );
232	        }
233	
234	        cat.macros.push(macro_config);
235	        Ok(())
236	    }
