238	    /// Apply `updates` to the named macro in `category`, leaving all other fields unchanged.
239	    ///
240	    /// Errors if `category` or `macro_name` is not found.
241	    pub fn edit_macro(
242	        &mut self,
243	        category: &str,
244	        macro_name: &str,
245	        updates: MacroUpdates,
246	    ) -> Result<()> {
247	        let cat = self
248	            .pack
249	            .categories
250	            .iter_mut()
251	            .find(|c| c.name == category)
252	            .ok_or_else(|| anyhow::anyhow!("category '{}' not found", category))?;
253	
254	        let m = cat
255	            .macros
256	            .iter_mut()
257	            .find(|m| m.name == macro_name)
258	            .ok_or_else(|| {
259	                anyhow::anyhow!("macro '{}' not found in category '{}'", macro_name, category)
260	            })?;
261	
262	        if let Some(phrase) = updates.phrase {
263	            m.phrase = phrase;
264	        }
265	        if let Some(if_flag) = updates.if_flag {
266	            m.if_flag = if_flag;
267	        }
268	        if let Some(set_flag) = updates.set_flag {
269	            m.set_flag = set_flag;
270	        }
271	        if let Some(sound) = updates.sound {
272	            m.sound = sound;
273	        }
274	        if let Some(keys) = updates.keys {
275	            m.keys = keys;
276	        }
277	
278	        Ok(())
279	    }
