281	    /// Remove the named macro from `category`.
282	    ///
283	    /// Errors if `category` or `macro_name` is not found.
284	    pub fn remove_macro(&mut self, category: &str, macro_name: &str) -> Result<()> {
285	        let cat = self
286	            .pack
287	            .categories
288	            .iter_mut()
289	            .find(|c| c.name == category)
290	            .ok_or_else(|| anyhow::anyhow!("category '{}' not found", category))?;
291	
292	        let idx = cat
293	            .macros
294	            .iter()
295	            .position(|m| m.name == macro_name)
296	            .ok_or_else(|| {
297	                anyhow::anyhow!("macro '{}' not found in category '{}'", macro_name, category)
298	            })?;
299	
300	        cat.macros.remove(idx);
301	        Ok(())
302	    }
