304	    /// Move `macro_name` from `from_category` to the end of `to_category`.
305	    ///
306	    /// Atomic: validates all preconditions before any mutation.
307	    /// Errors if either category is missing, the macro is missing from source,
308	    /// or a macro with the same name already exists in the destination.
309	    pub fn move_macro(
310	        &mut self,
311	        from_category: &str,
312	        to_category: &str,
313	        macro_name: &str,
314	    ) -> Result<()> {
315	        // Validate preconditions before any mutation.
316	        let from_idx = self
317	            .pack
318	            .categories
319	            .iter()
320	            .position(|c| c.name == from_category)
321	            .ok_or_else(|| anyhow::anyhow!("source category '{}' not found", from_category))?;
322	
323	        let to_idx = self
324	            .pack
325	            .categories
326	            .iter()
327	            .position(|c| c.name == to_category)
328	            .ok_or_else(|| anyhow::anyhow!("destination category '{}' not found", to_category))?;
329	
330	        let macro_idx = self.pack.categories[from_idx]
331	            .macros
332	            .iter()
333	            .position(|m| m.name == macro_name)
334	            .ok_or_else(|| {
335	                anyhow::anyhow!(
336	                    "macro '{}' not found in category '{}'",
337	                    macro_name,
338	                    from_category
339	                )
340	            })?;
341	
342	        if self.pack.categories[to_idx]
343	            .macros
344	            .iter()
345	            .any(|m| m.name == macro_name)
346	        {
347	            bail!(
348	                "macro '{}' already exists in destination category '{}'",
349	                macro_name,
350	                to_category
351	            );
352	        }
353	
354	        // All checks passed — mutate atomically.
355	        let moved = self.pack.categories[from_idx].macros.remove(macro_idx);
356	        self.pack.categories[to_idx].macros.push(moved);
357	        Ok(())
358	    }
359	
360	    /// Rename `old_name` category to `new_name` in place (preserves index and macros).
361	    ///
362	    /// Errors if `old_name` is not found, if `new_name == old_name`, or if `new_name` is already in use.
363	    pub fn rename_category(&mut self, old_name: &str, new_name: &str) -> Result<()> {
364	        if old_name == new_name {
365	            bail!("new category name '{}' is identical to the old name", new_name);
366	        }
367	
368	        if self.pack.categories.iter().any(|c| c.name == new_name) {
369	            bail!("category '{}' already exists", new_name);
370	        }
371	
372	        let cat = self
373	            .pack
374	            .categories
375	            .iter_mut()
376	            .find(|c| c.name == old_name)
377	            .ok_or_else(|| anyhow::anyhow!("category '{}' not found", old_name))?;
378	
379	        cat.name = new_name.to_string();
380	        Ok(())
381	    }
382	
383	    /// Append a new empty category with `name` to the end of `pack.categories`.
384	    ///
385	    /// Errors if `name` is already in use.
386	    pub fn add_category(&mut self, name: &str) -> Result<()> {
387	        if self.pack.categories.iter().any(|c| c.name == name) {
388	            bail!("category '{}' already exists", name);
389	        }
390	
391	        self.pack.categories.push(Category {
392	            name: name.to_string(),
393	            macros: vec![],
394	        });
395	        Ok(())
396	    }
397	
398	    /// Remove the named category.
399	    ///
400	    /// Errors if `name` is not found or if the category still contains macros
401	    /// (caller must explicitly empty it first via `remove_macro`).
402	    pub fn remove_category(&mut self, name: &str) -> Result<()> {
403	        let idx = self
404	            .pack
405	            .categories
406	            .iter()
407	            .position(|c| c.name == name)
408	            .ok_or_else(|| anyhow::anyhow!("category '{}' not found", name))?;
409	
410	        if !self.pack.categories[idx].macros.is_empty() {
411	            bail!(
412	                "category '{}' still has {} macro(s); empty it first",
413	                name,
414	                self.pack.categories[idx].macros.len()
415	            );
416	        }
417	
418	        self.pack.categories.remove(idx);
419	        Ok(())
420	    }
421	}
